() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  const products = [];
  const productCards = document.querySelectorAll('.card');

  productCards.forEach((card, index) => {
    const titleLink = card.querySelector('.card-block h4 a');
    const priceElement = card.querySelector('.card-block h5');
    const imageLink = card.querySelector('a[href*="prod.html"]');

    if (titleLink && priceElement) {
      const name = titleLink.textContent.trim();
      const price = priceElement.textContent.trim();
      const productUrl = imageLink ? new URL(imageLink.getAttribute('href'), window.location.href).href : null;
      const xpath = getXPath(titleLink);

      products.push({
        record_id: (index + 1).toString(),
        name: name,
        price: price,
        rating: null,
        availability: null,
        product_url: productUrl,
        source_url: "https://www.demoblaze.com/",
        source_xpath: xpath
      });
    }
  });

  return products;
}

